 183→router.get('/getFollowsData', async(req, res) => {
 184→    const {userId, loggedInUserId} = req.query;
 185→    if(!userId && !loggedInUserId) return res.status(400).json({error: 'userId or loggendUserId is undefined '});
 186→    // console.log(req.query)
 187→    try {
 188→        const followersCountPromise = supabase
 189→        .from('follows')
 190→        .select('*', {count: 'exact', head: true})
 191→        .eq('following_id', userId);
 192→
 193→        const followingCountPromise = supabase
 194→        .from('follows')
 195→        .select('*', {count: 'exact', head: true})
 196→        .eq('follower_id', userId)
 197→
 198→        const isFollowingPromise = supabase
 199→        .from('follows')
 200→        .select('*', {count: 'exact', head: true})
 201→        .eq('follower_id', loggedInUserId)
 202→        .eq('following_id', userId)
 203→
 204→        const [followersCountResult, followingsCountResult, isFollowingResult] = await Promise.all([
 205→            followersCountPromise, followingCountPromise, isFollowingPromise,
 206→        ])
 207→
 208→
 209→        const {count: followersCount, error: errorFollowers } = followersCountResult;
 210→        const {count: followingsCount, error: errorFollowings} = followingsCountResult;
 211→        const {count: isFollowingCount, error: errorIsfollowing} = isFollowingResult;
 212→
 213→        if(errorFollowers || errorFollowings || errorIsfollowing){
 214→            console.error('supabase error while fetching data:', errorFollowers.message, errorFollowings.message, errorIsfollowing.message)
 215→            return res.status(500).json({error: 'failed to fetch data'})
 216→        }
 217→
 218→        return res.status(200).json({
 219→            followersCount: followersCount,
 220→            followingsCount: followingsCount,
 221→            isFollowing: isFollowingCount > 0
 222→        })
 223→
 224→    } catch (error) {
 225→        console.error('Error in Promise.all:', error);
 226→        res.status(500).json({ error: 'An unexpected error occurred' });
 227→    }
 228→
 229→})
