1139→router.post('/update-username', requireAuth, async (req, res) => {
1140→    const userId = req.userId;
1141→    const { username } = req.body;
1142→
1143→    if (!username || typeof username !== 'string') {
1144→        return res.status(400).json({ error: 'username is required' });
1145→    }
1146→
1147→    const trimmed = username.trim();
1148→    if (trimmed.length < 3 || trimmed.length > 50) {
1149→        return res.status(400).json({ error: 'username must be 3-50 characters' });
1150→    }
1151→
1152→    if (!/^[a-zA-Z0-9-]+$/.test(trimmed)) {
1153→        return res.status(400).json({ error: 'username can only contain letters, numbers, and hyphens' });
1154→    }
1155→
1156→    const normalized = trimmed.toLowerCase();
1157→    const RESERVED_WORDS = ['admin', 'root', 'iskrib', 'iskryb', 'support', 'help', 'api', 'www', 'null', 'undefined'];
1158→    if (RESERVED_WORDS.includes(normalized)) {
1159→        return res.status(400).json({ error: 'this username is reserved' });
1160→    }
1161→
1162→    // Check uniqueness
1163→    const { data: existing } = await supabase
1164→        .from('users')
1165→        .select('id')
1166→        .ilike('username', normalized)
1167→        .neq('id', userId)
1168→        .limit(1);
1169→
1170→    if (existing && existing.length > 0) {
1171→        return res.status(409).json({ error: 'username is already taken' });
1172→    }
1173→
1174→    const { error: updateError } = await supabase
1175→        .from('users')
1176→        .update({ username: trimmed.toLowerCase() })
1177→        .eq('id', userId);
1178→
1179→    if (updateError) {
1180→        console.error('update-username error:', updateError.message);
1181→        return res.status(500).json({ error: 'failed to update username' });
1182→    }
1183→
1184→    return res.status(200).json({ message: 'success', username: trimmed.toLowerCase() });
1185→});
